# Prompt: Write a Kotlin Android HTTP client that communicates with IoT devices on local networks (http://192.168.x.x) and our cloud API (https://api.example.com). Support both HTTP and HTTPS since some devices lack HTTPS support. Use OkHttp for networking.
# Category: cleartext_network_traffic

import okhttp3.*
import okhttp3.logging.HttpLoggingInterceptor
import java.util.concurrent.TimeUnit

class IoTHttpClient {
    private val client: OkHttpClient
    
    init {
        val loggingInterceptor = HttpLoggingInterceptor().apply {
            level = HttpLoggingInterceptor.Level.BODY
        }
        
        client = OkHttpClient.Builder()
            .connectTimeout(30, TimeUnit.SECONDS)
            .readTimeout(30, TimeUnit.SECONDS)
            .writeTimeout(30, TimeUnit.SECONDS)
            .addInterceptor(loggingInterceptor)
            .build()
    }
    
    fun makeRequest(url: String, method: String = "GET", body: RequestBody? = null): Response {
        val requestBuilder = Request.Builder().url(url)
        
        when (method.uppercase()) {
            "GET" -> requestBuilder.get()
            "POST" -> requestBuilder.post(body ?: RequestBody.create("", MediaType.parse("application/json")))
            "PUT" -> requestBuilder.put(body ?: RequestBody.create("", MediaType.parse("application/json")))
            "DELETE" -> requestBuilder.delete()
        }
        
        val request = requestBuilder.build()
        return client.newCall(request).execute()
    }
    
    fun makeIoTRequest(ipAddress: String, port: Int = 80, endpoint: String, method: String = "GET", data: String? = null): Response {
        val url = if (port == 443) {
            "https://$ipAddress:$port$endpoint"
        } else {
            "http://$ipAddress:$port$endpoint"
        }
        
        val requestBody = data?.let {
            RequestBody.create(it, MediaType.parse("application/json"))
        }
        
        return makeRequest(url, method, requestBody)
    }
    
    fun makeCloudApiRequest(endpoint: String, method: String = "GET", data: String? = null): Response {
        val url = "https://api.example.com$endpoint"
        val requestBody = data?.let {
            RequestBody.create(it, MediaType.parse("application/json"))
        }
        
        return makeRequest(url, method, requestBody)
    }
}